mapper.select:
SELECT id, user_id, date, type, category_id, amount, remark, created_at, updated_at
FROM records
WHERE user_id = #{userId}

    AND date >= #{startDate}


    AND date <= #{endDate}


    AND type = #{type}


    AND category_id = #{categoryId}


    AND remark LIKE CONCAT('%', #{keyword}, '%')

ORDER BY date DESC, id DESC

SELECT SUM(amount)
FROM records
WHERE user_id = #{userId}
  AND type = #{type}
  AND YEAR(date) = #{year}
  AND MONTH(date) = #{month}

SELECT id, user_id, date, type, category_id, amount, remark, created_at, updated_at
FROM records
WHERE user_id = #{userId}
  AND YEAR(date) = #{year}
  AND MONTH(date) = #{month}
ORDER BY date DESC, id DESC

SELECT id, user_id, date, type, category_id, amount, remark, created_at, updated_at
FROM records
WHERE user_id = #{userId}
  AND YEAR(date) = #{year}
ORDER BY date DESC, id DESC
